struct Solution {}

impl Solution {
    pub fn rotate(nums: &mut Vec<i32>, k: i32) {
        let k = k as usize % nums.len();
        nums.reverse();
        nums[..k].reverse();
        nums[k..].reverse();
    }
}

fn what(mut nums: Vec<i32>, k: i32) {
    Solution::rotate(&mut nums, k);
    println!("{:?}", nums);
}

fn main() {
    // Input: nums = [1,2,3,4,5,6,7], k = 3
